#nullable enable // autogenerated

using TMPro;
using UnityEngine;
using UnityEngine.UI;

namespace MVZ2.UI.Level
{
    public class HPBar : MonoBehaviour
    {
        public void UpdateBar(HPBarViewData data)
        {
            SetBarColor(data.barColor);
            SetBarFill(data.barAmount);
            SetText(data.text);
            SetIcon(data.icon);
        }
        public void SetBarColor(Color color)
        {
            barImage.color = color;
        }
        public void SetBarFill(float value)
        {
            barImage.fillAmount = value;
        }
        public void SetText(string text)
        {
            this.text.text = text;
        }
        public void SetIcon(Sprite? sprite)
        {
            icon.sprite = sprite;
            icon.enabled = sprite;
        }
        [SerializeField]
        private Image barImage = null!;
        [SerializeField]
        private TextMeshProUGUI text = null!;
        [SerializeField]
        private Image icon = null!;
    }
    public struct HPBarViewData
    {
        public Color barColor;
        public float barAmount;
        public string text;
        public Sprite? icon;
    }
}
